.rom_type
    equb &82                                                          ; 8006: 82          .        ; ROM type: service + language
.copyright_offset
    equb copyright - rom_header                                       ; 8007: 19          .     
.binary_version
    equb &04                                                          ; 8008: 04          .     
.title
    equs "Acorn ANFS 4.21", &00                                       ; 8009: 41 63 6f... Aco...
