    equb &00, "(C)1986 Acorn", &00                                    ; 8019: 00 28 43... .(C...   ; Null terminator before copyright
; ***************************************************************************************
; Service 5: unrecognised interrupt (Master 128 dispatch)
;
; Reads the deferred-work flag at &0D65; if zero, returns early via PLX/PLY/RTS.
; Otherwise clears bit 7 of the Master 128 ACCCON register at &FE34 (TRB), zeros &0D65,
; then dispatches one of two ways depending on bit 7 of the saved Y:
;
; | Caller Y bit 7 | Action                                                                |
; |----------------|-----------------------------------------------------------------------|
; | Set            | Dispatch via the PHA/PHA/RTS table at dispatch_svc5                   |
; | Clear          | Fire Econet RX event &FE via generate_event, then JMP to tx_done_exit |
;
; On Entry:
;     A: 5 (service call number)
;     X: ROM slot
;     Y: parameter (high bit selects dispatch path)
.svc5_irq_check
    phx                                                               ; 8028: da          .        ; Save X (the ROM slot we're being called on behalf of)
    phy                                                               ; 8029: 5a          Z        ; Save Y (the dispatch-path selector via its high bit)
    ldy tx_op_type                                                    ; 802a: ac 65 0d    .e.      ; Read deferred-work flag at &0D65 (set by NMI when work queued)
    bne irq_check_dispatch                                            ; 802d: d0 03       ..       ; Non-zero: there's work to dispatch
    ply                                                               ; 802f: 7a          z        ; Zero: no work; restore Y
    plx                                                               ; 8030: fa          .        ; Restore X
    rts                                                               ; 8031: 60          `        ; Return to MOS (service unclaimed)
; &8032 referenced 1 time by &802d
.irq_check_dispatch
    lda #&80                                                          ; 8032: a9 80       ..       ; A=&80: bit 7 -- the bit to clear in ACCCON
    trb acccon                                                        ; 8034: 1c 34 fe    .4.      ; Clear ACCCON bit 7 (release IRR mask)
    stz tx_op_type                                                    ; 8037: 9c 65 0d    .e.      ; Zero the deferred-work flag (we're handling it now)
    tya                                                               ; 803a: 98          .        ; Copy to A for sign test  Bring saved Y back into A so BMI can test bit 7
    bmi dispatch_svc5                                                 ; 803b: 30 0b       0.       ; Bit 7 set: dispatch via table  Bit 7 of caller's Y set: dispatch via PHA/PHA/RTS table
    lda #&fe                                                          ; 803d: a9 fe       ..       ; A=&FE: Econet receive event
    jsr generate_event                                                ; 803f: 20 45 80     E.      ; Call event vector handler
    jmp tx_done_exit                                                  ; 8042: 4c 82 85    L..      ; Fire event (enable: *FX52,150)  Tail-jump to tx_done_exit which restores X/Y and claims the service
; ***************************************************************************************
; Generate event via EVNTV
;
; Single-instruction JMP (evntv) that hands control to whatever handler is hooked into
; the MOS event vector. Called via service call &05 (svc5_irq_check) on a 'transmit
; complete' or 'receive complete' edge so user/MOS code can react to network events.
;
; On Entry:
;     A: event number
;
; On Exit:
;     A: preserved
;     X: preserved
;     Y: preserved
; &8045 referenced 1 time by &803f
.generate_event
    jmp (evntv)                                                       ; 8045: 6c 20 02    l .      ; Dispatch through event vector
; ***************************************************************************************
; Service-5 PHA/PHA/RTS dispatch tail
;
; Builds an RTS-target on the stack from the tx_done_dispatch_lo low-byte table and a
; hard- coded high byte of &85, then falls through into the shared svc_5_unknown_irq RTS
; to land on the matching tx_done_dispatch_lo+Y page-&85 handler.
;
; On Entry:
;     Y: tx_done_dispatch_lo offset (post-&83 base bias)
; &8048 referenced 1 time by &803b
.dispatch_svc5
    lda #&85                                                          ; 8048: a9 85       ..       ; Push return addr high (&85)
    pha                                                               ; 804a: 48          H        ; High byte on stack for RTS
    lda tx_done_dispatch_lo-&83,y                                     ; 804b: b9 b8 84    ...      ; Load dispatch target low byte
    pha                                                               ; 804e: 48          H        ; Low byte on stack for RTS
; ***************************************************************************************
; Service-5 unknown-IRQ tail (PHA/PHA/RTS landing)
;
; Bare RTS reused as the final step of every dispatch_svc5 entry. With the target's
; high/low bytes already pushed by the caller, RTS jumps to the selected handler. Also
; reached as the unclaimed-IRQ tail of the service-5 prologue when no ANFS handler
; matches.
.svc_5_unknown_irq
    rts                                                               ; 804f: 60          `        ; RTS = dispatch to PHA'd address
; ***************************************************************************************
; ADLC initialisation
;
; Initialise ADLC hardware and Econet workspace. Disables NMIs via BIT master_intoff (the
; Master 128 INTOFF register at &FE38; the Model-B equivalent reads econet_station_id at
; &FE18 for the same side effect). Performs a full ADLC reset via adlc_full_reset, then
; probes for a Tube co-processor via OSBYTE &EA and stores the result in tube_present.
; Issues an NMI-claim service request (OSBYTE &8F, X=&0C). Falls through to
; init_nmi_workspace to copy the NMI shim to RAM.
; &8050 referenced 1 time by &903c
.adlc_init
