; ***************************************************************************************
; Service call dispatch (Master 128)
;
; Handles service calls 1, 4, 8, 9, 13, 14, and 15.
;
; | Call | Meaning                     |
; |------|-----------------------------|
; | 1    | Absolute workspace claim    |
; | 4    | Unrecognised * command      |
; | 8    | Unrecognised OSWORD         |
; | 9    | *HELP                       |
; | 13   | ROM initialisation          |
; | 14   | ROM initialisation complete |
; | 15   | Vectors claimed             |
;
; On service 15 the ROM verifies the host OS via OSBYTE 0 with the input X=1, which
; returns the OS version code:
;
; | OSBYTE 1 value | Host                              |
; |----------------|-----------------------------------|
; | 0              | OS 1.00 (early BBC B or Electron) |
; | 1              | OS 1.20 or American OS            |
; | 2              | OS 2.00 (BBC B+)                  |
; | 3              | OS 3.2 / 3.5 (Master 128)         |
; | 4              | OS 4.0 (Master Econet Terminal)   |
; | 5              | OS 5.0 (Master Compact)           |
;
; Only Master 128 and Master Econet Terminal are supported. Any other version gets a Bad
; ROM <slot> message printed and its workspace byte cleared at &02A0 + adjusted-slot,
; effectively rejecting the ROM.
;
; On Entry:
;     A: service call number
;     X: ROM slot
;     Y: parameter
; &8a54 referenced 1 time by &8003
.service_handler
    pha                                                               ; 8a54: 48          H        ; Save service call number
    cmp #&0f                                                          ; 8a55: c9 0f       ..       ; Service call &0F (vectors claimed)?
    bne restore_rom_slot_entry                                        ; 8a57: d0 34       .4       ; No: skip vectors-claimed handling
    phy                                                               ; 8a59: 5a          Z        ; Save Y on stack across the version-check
    lda #osbyte_read_os_version                                       ; 8a5a: a9 00       ..       ; OSBYTE 0: read OS version
    ldx #1                                                            ; 8a5c: a2 01       ..       ; X=1 to request version number
    jsr osbyte                                                        ; 8a5e: 20 f4 ff     ..      ; X=1, OS 1.20 or American OS
; X is the OS version number:
;
; | X | Meaning                                   |
; |---|-------------------------------------------|
; | 0 | OS 1.00 (Early BBC B or Electron OS 1.00) |
; | 1 | OS 1.20 or American OS                    |
; | 2 | OS 2.00 (BBC B+)                          |
; | 3 | OS 3.2/3.5 (Master 128)                   |
; | 4 | OS 4.0 (Master Econet Terminal)           |
; | 5 | OS 5.0 (Master Compact)                   |
    cpx #3                                                            ; 8a61: e0 03       ..       ; OS 3.2/3.5 (Master 128)?
    beq restore_rom_slot                                              ; 8a63: f0 25       .%       ; Yes: target OS, skip Bad ROM message
    cpx #4                                                            ; 8a65: e0 04       ..       ; OS 4.0 (Master Econet Terminal)?
    beq restore_rom_slot                                              ; 8a67: f0 21       .!       ; Yes: target OS, skip Bad ROM message
    txa                                                               ; 8a69: 8a          .        ; Transfer OS version to A
    php                                                               ; 8a6a: 08          .        ; Save flags (Z set if OS 1.00) across print
    jsr print_inline                                                  ; 8a6b: 20 61 92     a.      ; Print '<CR>Bad ROM ' to mark non-Master OS
    equb &0d, "Bad ROM "                                              ; 8a6e: 0d 42 61... .Ba...   ; svc 13 fail path
    lda romsel_copy                                                   ; 8a77: a5 f4       ..       ; Load this ROM's slot number
    jsr print_num_no_leading                                          ; 8a79: 20 27 b3     '.      ; Print slot number as decimal
    jsr print_newline_no_spool                                        ; 8a7c: 20 f9 91     ..      ; Print trailing newline, bypassing *SPOOL
    ldx romsel_copy                                                   ; 8a7f: a6 f4       ..       ; Reload ROM slot for workspace clearing
    plp                                                               ; 8a81: 28          (        ; Restore flags
    beq clear_workspace_byte                                          ; 8a82: f0 01       ..       ; OS 1.00: skip INX (table starts at slot 0)
    inx                                                               ; 8a84: e8          .        ; Adjust index for OS 1.20/2.00/5.00 layout
; &8a85 referenced 1 time by &8a82
.clear_workspace_byte
    lda #0                                                            ; 8a85: a9 00       ..       ; A=0
    sta rom_type_table,x                                              ; 8a87: 9d a0 02    ...      ; Clear workspace byte for this ROM
; &8a8a referenced 2 times by &8a63, &8a67
.restore_rom_slot
    ldx romsel_copy                                                   ; 8a8a: a6 f4       ..       ; Restore ROM slot to X
    ply                                                               ; 8a8c: 7a          z        ; Restore Y from stack
; &8a8d referenced 1 time by &8a57
.restore_rom_slot_entry
    pla                                                               ; 8a8d: 68          h        ; Pop service call number into A
    pha                                                               ; 8a8e: 48          H        ; Re-save service call number
    cmp #&24 ; '$'                                                    ; 8a8f: c9 24       .$       ; Service call &24 (Dynamic Workspace requirements)?
    bne check_adlc_flag                                               ; 8a91: d0 0e       ..       ; No: skip ADLC check
    lda adlc_cr1                                                      ; 8a93: ad a0 fe    ...      ; Read ADLC status register 1
    and #&10                                                          ; 8a96: 29 10       ).       ; Mask relevant status bits
    bne check_adlc_flag                                               ; 8a98: d0 07       ..       ; Non-zero: ADLC absent, set flag
.set_adlc_absent
