    sec                                                               ; 8a9d: 38          8        ; Set carry to mark ADLC absent
    ror rom_ws_pages,x                                                ; 8a9e: 7e f0 0d    ~..      ; Rotate carry into bit 7 of slot flag
; &8aa1 referenced 2 times by &8a91, &8a98
.check_adlc_flag
    lda rom_ws_pages,x                                                ; 8aa1: bd f0 0d    ...      ; Load ROM slot flag byte
    asl a                                                             ; 8aa4: 0a          .        ; Shift bit 7 (ADLC absent) into carry
    pla                                                               ; 8aa5: 68          h        ; Restore service call number
    bcc dispatch_svc_with_state                                       ; 8aa6: 90 01       ..       ; ADLC present: continue dispatch
    rts                                                               ; 8aa8: 60          `        ; ADLC absent: decline service, return
; &8aa9 referenced 1 time by &8aa6
.dispatch_svc_with_state
    tax                                                               ; 8aa9: aa          .        ; Transfer service number to X
    lda svc_state                                                     ; 8aaa: a5 a9       ..       ; Save current service state
    pha                                                               ; 8aac: 48          H        ; Push old state
    txa                                                               ; 8aad: 8a          .        ; Restore service number to A
    sta svc_state                                                     ; 8aae: 85 a9       ..       ; Store as current service state
    cmp #&0d                                                          ; 8ab0: c9 0d       ..       ; Service < 13?
    bcc dispatch_svc_index                                            ; 8ab2: 90 1c       ..       ; Yes: use as dispatch index directly
    sbc #5                                                            ; 8ab4: e9 05       ..       ; Subtract 5 (map 13-17 to 8-12)
    cmp #&0d                                                          ; 8ab6: c9 0d       ..       ; Mapped value = 13? (original was 18)
    beq dispatch_svc_index                                            ; 8ab8: f0 16       ..       ; Yes: valid service 18 (FS select)
    bcc dispatch_svc_state_check                                      ; 8aba: 90 12       ..       ; C clear: service number was below the prior CMP threshold, take dispatch fall-through
    sbc #5                                                            ; 8abc: e9 05       ..       ; Subtract 5 to remap service range
    cmp #&0e                                                          ; 8abe: c9 0e       ..       ; Compare with &0E
    beq dispatch_svc_index                                            ; 8ac0: f0 0e       ..       ; Equal: dispatch directly
    bcc dispatch_svc_state_check                                      ; 8ac2: 90 0a       ..       ; Below: take dispatch fall-through
    sbc #8                                                            ; 8ac4: e9 08       ..       ; Subtract 8 to remap further
    cmp #&0f                                                          ; 8ac6: c9 0f       ..       ; Compare with &0F
    bcc dispatch_svc_state_check                                      ; 8ac8: 90 04       ..       ; Below: dispatch fall-through
    cmp #&18                                                          ; 8aca: c9 18       ..       ; Compare with &18
    bcc dispatch_svc_index                                            ; 8acc: 90 02       ..       ; Below: dispatch index now in A
; &8ace referenced 3 times by &8aba, &8ac2, &8ac8
.dispatch_svc_state_check
    lda #0                                                            ; 8ace: a9 00       ..       ; Unknown service: set index to 0
; &8ad0 referenced 4 times by &8ab2, &8ab8, &8ac0, &8acc
.dispatch_svc_index
    tax                                                               ; 8ad0: aa          .        ; Transfer dispatch index to X
    beq restore_svc_state                                             ; 8ad1: f0 0e       ..       ; Index 0: unhandled service, skip
    lda ws_page                                                       ; 8ad3: a5 a8       ..       ; Save current workspace page
    pha                                                               ; 8ad5: 48          H        ; Push old page
    sty ws_page                                                       ; 8ad6: 84 a8       ..       ; Set workspace page from Y parameter
    tya                                                               ; 8ad8: 98          .        ; Transfer Y to A
    ldy #0                                                            ; 8ad9: a0 00       ..       ; Y=0 for dispatch offset
    jsr svc_dispatch                                                  ; 8adb: 20 61 8e     a.      ; Dispatch to service handler via table
    pla                                                               ; 8ade: 68          h        ; Restore old workspace page
    sta ws_page                                                       ; 8adf: 85 a8       ..       ; Store it back
; &8ae1 referenced 1 time by &8ad1
.restore_svc_state
    ldx svc_state                                                     ; 8ae1: a6 a9       ..       ; Get service state (return code)
    pla                                                               ; 8ae3: 68          h        ; Restore old service state
    sta svc_state                                                     ; 8ae4: 85 a9       ..       ; Store it back
    txa                                                               ; 8ae6: 8a          .        ; Transfer return code to A
.restore_romsel_rts
    ldx romsel_copy                                                   ; 8ae7: a6 f4       ..       ; Restore ROM slot to X
    rts                                                               ; 8ae9: 60          `        ; Return to MOS
; ***************************************************************************************
; *ROFF command handler
;
; Disables remote operation by clearing the flag at offset 0 in the receive block. If
; remote operation was active, re-enables the keyboard via OSBYTE &C9 (with X=0, Y=0) and
; calls tx_econet_abort with A=&0A to reinitialise the workspace area. Falls through to
; scan_remote_keys which clears svc_state and nfs_workspace.
