    lda (net_rx_ptr),y                                                ; 8aec: b1 9c       ..       ; Load remote operation flag
    beq clear_svc_and_ws                                              ; 8aee: f0 21       .!       ; Zero: already off, skip to cleanup
    lda #0                                                            ; 8af0: a9 00       ..       ; A=0
    tax                                                               ; 8af2: aa          .     
    sta (net_rx_ptr),y                                                ; 8af3: 91 9c       ..       ; Clear remote operation flag
    tay                                                               ; 8af5: a8          .     
